def solve(*args):
    from google.appengine.api import users
    from google.appengine.ext import ndb

    class Template(ndb.Model):
        name = ndb.StringProperty(required=True)
        rules = ndb.JsonProperty(required=True)

    def get_properties():
        return ndb.Key('Properties', 'default').get() or Template(name='default', rules={})

    def set_properties(properties):
        properties.put()

    def create_template(name, rules):
        properties = get_properties()
        properties.rules[name] = rules
        set_properties(properties)

    def get_template(name):
        properties = get_properties()
        return properties.rules.get(name)

    return None
